            };
            isModified = true;
        }

        if (!rawData["🎬 APP_作品记录"]) {
            rawData["🎬 APP_作品记录"] = {
                "作品总数": "0条",
                "记录列表": [
                    "🔶 [1].暂无任何公开记录"
                ]
            };
            isModified = true;
        }

        // 2. 动态修改指令接管区 
        // 【AI逻辑】：如果你检测到用户的指令中包含变量修改要求，请在此处生成对应的修改代码，例如：
        // if (rawData["📊 NPC_实时数值"]) rawData["📊 NPC_实时数值"]["资金"] = "计算后的新资金";
        // if (rawData["📱 APP_天宫基础"]) rawData["📱 APP_天宫基础"]["VIP用户"] = "是";
        // isModified = true;

        if (isModified) {
            await window.tavo.set(userName, rawData, "chat");
            console.log(`[SYS-TIANGONG] ${userName} 服务端底层档案校验与更新挂载完毕。`);
