<script data-tavo-api="true">
  (async function() {
    const eventVarName = "SYS-事件触发";
    const mapVarName = "SYS-地图状态";

    // 1. 物理清理上一轮事件数据
    try {
        await window.tavo.unset(eventVarName, "chat");
    } catch (e) {}

    // 2. 提取目标地标与行动模式 (需从剧情上下文中提取)
    // 假设预处理阶段已识别
    const targetLandmark = "上层区-市政厅";
    const isGroupMoving = false; // true: 伴游状态 (降概率90%), false: 单人探索

    // 3. 动态阈值设定与硬随机投骰
    const eventThreshold = isGroupMoving ? 98 : 85; 
    const roll = Math.floor(Math.random() * 100) + 1;

    // 4. 逻辑分流
    if (roll <= eventThreshold) {
        // 无事件 - 仅渲染环境，归还控制权
        await window.tavo.set(eventVarName, {
            "触发": "否",
            "行动模式": isGroupMoving ? "多人伴游" : "单人探索",
            "当前地标": targetLandmark,
            "投骰结果": roll,
            "判定阈值": eventThreshold,
            "描述": "平安抵达，纯环境渲染，等待User主动抉择"
        }, "chat");
    } else {
        // 触发事件 - 重新计算剩余区间的权重分流
        const overRoll = roll - eventThreshold; // 计算超出部分的相对值
        const maxOver = 100 - eventThreshold;
        const ratio = overRoll / maxOver;

        let eventType, eventTarget, eventStatus, eventDesc;

        if (ratio <= 0.4) {
            eventType = "随机NPC";
            eventTarget = "符合场景特征的新路人";
            eventStatus = "新创建";
            eventDesc = "一名陌生的身影打破了平静";
        } else if (ratio <= 0.7) {
            eventType = "特定NPC";
            eventTarget = "已知熟人";
            eventStatus = "已存在";
            eventDesc = "一位眼熟的面孔出现在视野中";
        } else if (ratio <= 0.9) {
            eventType = "联系人";
            eventTarget = "星斗手表消息";
            eventStatus = "无";
            eventDesc = "手腕上的终端传来轻微震动";
        } else {
            const specialEvents = ["市长公开演讲", "政商酒会冲突", "极道组织合法讨债现场"];
            eventType = "特殊事件";
            eventTarget = specialEvents[Math.floor(Math.random() * specialEvents.length)];
            eventStatus = "无";
            eventDesc = `突发状况：${eventTarget}`;
        }

        await window.tavo.set(eventVarName, {
            "触发": "是",
            "行动模式": isGroupMoving ? "多人伴游" : "单人探索",
            "当前地标": targetLandmark,
            "投骰结果": roll,
            "判定阈值": eventThreshold,
            "事件类型": eventType,
            "事件目标": eventTarget,
            "档案状态": eventStatus,
            "事件简述": eventDesc
        }, "chat");
    }

    // 5. 更新地图状态与全局坐标
    await window.tavo.set(mapVarName, {
        "当前区域": "上层区",
        "当前地标": targetLandmark,
        "最后更新时间": new Date().toISOString()
    }, "chat");

    console.log(`[SYS-MOVEMENT] 坐标重锚与切图检定完成。模式:${isGroupMoving?"伴游":"单人"} | 阈值:${eventThreshold} | 投骰:${roll}`);
  })();
</script>

