        #cw-social-ui .profile-avatar-box { width: 64px; height: 64px; border-radius: 6px; display: flex; align-items: center; justify-content: center; font-size: 30px; margin-right: 20px; flex-shrink: 0; color:#fff; font-weight:bold;}
        #cw-social-ui .profile-info { flex: 1; display: flex; flex-direction: column; justify-content: center; }
