        #cw-social-ui .video-item:active { opacity: 0.7; }
        #cw-social-ui .video-thumb { width: 100px; height: 100px; background: #333; border-radius: 8px; display: flex; align-items: center; justify-content: center; font-size: 14px; color: #fff; font-weight: bold; position: relative; margin-bottom: 8px; box-shadow: 0 2px 6px rgba(0,0,0,0.15); text-align: center; padding: 0 5px;}
        #cw-social-ui .video-thumb::after { content: '▷'; position: absolute; right: 6px; bottom: 4px; font-size: 14px; color: rgba(255,255,255,0.9); }
        #cw-social-ui .video-title { font-size: 12px; color: #333; text-align: center; line-height: 1.3; width: 100px; word-break: break-all; white-space: normal; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; }
        #cw-social-ui .action-btn { display: flex; align-items: center; justify-content: center; padding: 16px; background: #ffffff; color: #576b95; font-size: 17px; font-weight: 600; cursor: pointer; gap: 8px; transition: background 0.1s; }
