        #cw-social-ui .cwc-modal { display: none; position: absolute; top: 0; left: 0; width: 100%; height: 100%; background: rgba(0,0,0,0.5); z-index: 100; align-items: center; justify-content: center; }
        #cw-social-ui .cwc-modal-box { background: #ffffff; width: 80%; border-radius: 12px; padding: 20px; text-align: center; box-shadow: 0 10px 30px rgba(0,0,0,0.2); }
        #cw-social-ui .cwc-btn-group { display: flex; justify-content: space-between; margin-top: 20px; gap: 10px; }
        #cw-social-ui .cwc-modal-btn { flex: 1; padding: 12px 0; border: none; border-radius: 6px; font-weight: bold; cursor: pointer; font-size:15px; }
        #cw-social-ui .cwc-btn-cancel { background: #f2f2f2; color: #111111; }
        #cw-social-ui .cwc-btn-confirm { background: #07c160; color: #ffffff; }
        #cw-social-ui .cwc-btn-danger { background: #fa5151; color: #ffffff; }
        #cw-social-ui .cwc-input-field { width: 100%; padding: 10px; margin-top: 15px; border: 1px solid #d9d9d9; border-radius: 6px; box-sizing: border-box; font-size: 14px; outline: none; }
        #cw-social-ui .cwc-input-field:focus { border-color: #07c160; }
    </style>

    <!-- Global Top Time Bar -->
    <div class="social-top-bar" id="sys-time-bar">--:--</div>

    <!-- ================= VIEW 1: CHAT ================= -->
    <div id="view-chat" style="display:flex; flex-direction:column; flex:1; height:100%;">
        <div class="ui-header">
            <div class="ui-btn" onclick="window.cwcActionBack()">🔙</div>
            <div class="ui-title" id="cwc-title-render" onclick="window.cwcShowView('profile')">未知联系人</div>
            <div class="ui-btn" style="color:#fa5151; font-size:24px; padding-bottom:4px;" onclick="window.cwcActionBlock()">×</div>
        </div>
        <div class="chat-body" id="cw-chat-scroll">
            <div id="cwc-render-msgs"></div>
        </div>
        <div class="cwc-chat-input-area">
            <input type="text" id="cwc-direct-input" class="cwc-real-input" placeholder="输入消息..." onkeypress="if(event.key === 'Enter') window.cwcDirectSend()">
            <button class="cwc-real-send" onclick="window.cwcDirectSend()">发送</button>
        </div>
    </div>

    <!-- ================= VIEW 2: PROFILE ================= -->
    <div id="view-profile" class="profile-view">
        <div class="ui-header" style="background:#fff;">
            <div class="ui-btn" onclick="window.cwcShowView('chat')">🔙</div>
            <div class="ui-title" style="cursor:default;">详细资料</div>
            <div class="ui-btn" style="visibility:hidden;">🔙</div>
        </div>
        <div class="profile-header">
            <div class="profile-avatar-box" id="prof-avatar">?</div>
            <div class="profile-info">
                <div class="name-row">
                    <div class="name-text" id="prof-nickname">昵称</div>
                    <div class="star-icon" id="prof-gender">♀</div>
                </div>
                <div class="sub-text" id="prof-name">姓名：</div>
                <div class="sub-text" id="prof-loc">地区：</div>
            </div>
        </div>

        <div class="section-group">
            <div class="info-row row-clickable" onclick="window.cwcActionEditRemark()">
                <div class="row-label muted">备注关系</div>
                <div class="row-value" style="flex-direction:row; justify-content:space-between; align-items:center;">
                    <span id="prof-remark-text">无</span>
                    <span class="arrow">修改 ✎</span>
                </div>
            </div>
            <div class="info-row">
                <div class="row-label muted">个性签名</div>
                <div class="row-value" id="prof-desc"></div>
            </div>
        </div>

        <div class="section-group" id="prof-tiangong-section">
            <div class="info-row row-clickable" onclick="window.cwcShowModal('是否访问对方的天宫圈空间？', ()=>{window.cwcCloseModal();})">
                <div class="row-label" style="color:#07c160; font-weight:bold;">🌌 天宫圈</div>
                <div class="row-value" style="flex-direction: row; justify-content: flex-end; align-items: center; color: #999; font-size: 14px;" id="prof-tiangong-rank"></div>
                <div class="arrow" style="color:#b2b2b2; font-family:consolas,monospace; font-weight:300;">&gt;</div>
            </div>
            <div id="prof-videos-wrapper">
                <div id="prof-videos-stats" style="padding: 10px 20px 0 20px; font-size: 14px; color: #111; font-weight: bold; background: #fff;"></div>
                <div class="video-scroll-container" id="prof-videos-container"></div>
            </div>
        </div>

        <div class="section-group" style="margin-top: 8px; margin-bottom: 20px; border-bottom: none;">
            <div class="action-btn" onclick="window.cwcShowView('chat')" style="border-bottom: 1px solid #e5e5e5;">
                <span class="action-icon">💬</span> 发消息
            </div>
            <div class="action-btn" onclick="window.cwcActionBlock()" style="color:#fa5151;">
                <span class="action-icon">❌</span> 删除/拉黑好友
            </div>
        </div>
    </div>

    <!-- ================= GLOBAL MODAL ================= -->
    <div id="cwc-global-modal" class="cwc-modal">
        <div class="cwc-modal-box">
            <div id="cwc-modal-msg" style="color:#111111; font-size:15px; margin-bottom:5px; line-height:1.6; font-weight:bold;"></div>
            <div id="cwc-modal-input-container"></div>
            <div class="cwc-btn-group">
                <button class="cwc-modal-btn cwc-btn-cancel" id="cwc-modal-cancel-btn" onclick="window.cwcCloseModal()">取消</button>
                <button class="cwc-modal-btn cwc-btn-confirm" id="cwc-modal-confirm-btn">确定</button>
            </div>
        </div>
    </div>

    <script data-tavo-api="true">
        // =====================================================================
        // 【AI 动态聊天与天宫圈资产同步区】
        // AI 在输出本面板时，必须严格读取底层变量并填充以下 DATA 对象。
        // 核心约束：
        // 1. mutualFollow: 判断 User 是否在对方【未知参数1】的"已关注"名单中。
        // 2. videos: 必须解析对方【未知参数2】(格式: [作品名]-致盲[是/否]-收费[值]金币-（简述）-购买者[名单])。
        //    * 如果User在购买者名单中，purchased设为 true。
        //    * 如果该视频明确设定致盲"是"且需要互相关注，requiresMutual设为 true。
        // =====================================================================
        const DATA = {
            sysTime: "[当前游戏时间]", 
            chat: {
                targetName: "[互动角色名]",
                messages: [
                    { type: "sys", text: "对方通过了你的好友申请" },
                    { type: "time", text: "19:08" },
                    { type: "left", avatar: "单", color: "#fa9d3b", text: "NPC基于道德与认知的拟人化真实回复" },
                    { type: "right", avatar: "我", color: "#07c160", text: "用户的台词" }
                ]
            },
            profile: {
                avatar: "[单字]",
                color: "#fa9d3b",
                nickname: "[目标昵称]",
                gender: "[♂/♀]",
                name: "[真实姓名]",
                location: "[地区与住址]",
                remark: "[读取未知参数1备注，默认：无]",
                desc: "[个性签名]",
                tiangongRank: "排名[值或未注册]",
                mutualFollow: false, // AI判定：User是否在对方的已关注列表中？
                videos: [
                    // AI 必须解析 【未知参数2】 填入此处，范例：
                    // {name: "洗澡偷拍", price: 50, color: "#a1c4fd", purchased: false, requiresMutual: false},
                    // {name: "私密日记", price: 0, color: "#ff9a9e", purchased: false, requiresMutual: true},
                    // {name: "打招呼", price: 0, color: "#8bd45e", purchased: true, requiresMutual: false}
                ]
            }
        };
        // =====================================================================

        document.getElementById('sys-time-bar').innerText = DATA.sysTime;

        // --- Tavo 原生发送钩子 ---
        window.cwcSendTavoCmd = function(text) {
            try {
                if (typeof tavo !== 'undefined' && tavo.input) {
                    tavo.input.set(text); tavo.input.send();
                } else {
                    const el = document.querySelector('textarea');
                    if (el) {
                        const setter = Object.getOwnPropertyDescriptor(window.HTMLTextAreaElement.prototype, 'value').set;
                        setter.call(el, text);
                        el.dispatchEvent(new Event('input', { bubbles: true }));
                        const sendBtn = document.querySelector('button[aria-label="Send"]') || document.querySelector('.send-button');
                        if(sendBtn) sendBtn.click();
                    }
                }
            } catch(e) { console.error('Tavo CMD Error:', e); }
            window.cwcCloseModal();
        };

        window.cwcDirectSend = function() {
            const inputEl = document.getElementById('cwc-direct-input');
            const val = inputEl.value.trim();
            if(!val) return;
            window.cwcSendTavoCmd(`=对[${DATA.chat.targetName}]发送：${val}`);
            inputEl.value = '';
        };

        window.cwcShowView = function(viewName) {
            document.getElementById('view-chat').style.display = (viewName === 'chat') ? 'flex' : 'none';
            document.getElementById('view-profile').style.display = (viewName === 'profile') ? 'flex' : 'none';
            if (viewName === 'chat') {
                setTimeout(() => {
                    const scrollArea = document.getElementById('cw-chat-scroll');
                    if(scrollArea) scrollArea.scrollTop = scrollArea.scrollHeight;
                }, 50);
            }
        };

        window.cwcShowModal = function(msg, confirmCallback, btnType = "normal", confirmText = "确定", cancelText = "取消", showInput = false) {
            const modal = document.getElementById('cwc-global-modal');
            const confirmBtn = document.getElementById('cwc-modal-confirm-btn');
            const cancelBtn = document.getElementById('cwc-modal-cancel-btn');
            const inputContainer = document.getElementById('cwc-modal-input-container');

            document.getElementById('cwc-modal-msg').innerHTML = msg;
            cancelBtn.innerText = cancelText;

            if (showInput) {
                inputContainer.innerHTML = `<input type="text" id="cwc-greet-input" class="cwc-input-field" placeholder="输入打招呼的信息...">`;
            } else {
                inputContainer.innerHTML = '';
            }

            if (btnType === "danger") {
                confirmBtn.className = "cwc-modal-btn cwc-btn-danger";
                confirmBtn.innerText = confirmText;
            } else {
                confirmBtn.className = "cwc-modal-btn cwc-btn-confirm";
                confirmBtn.innerText = confirmText;
            }

            confirmBtn.onclick = confirmCallback;
            modal.style.display = 'flex';
        };

        window.cwcCloseModal = function() {
            document.getElementById('cwc-global-modal').style.display = 'none';
        };

        window.cwcActionBack = function() {
            window.cwcShowModal("是否退出社交终端，返回现实世界？", () => {
                window.cwcSendTavoCmd(`=退出聊天`);
            }, "normal", "确定", "取消");
        };

        window.cwcActionBlock = function() {
            window.cwcShowModal(`是否删除/拉黑 [${DATA.chat.targetName}] ？<br><span style="color:#fa5151; font-size:12px; font-weight:normal;">警告：拉黑后可能会引发对方上门或极端的报复行为！</span>`, () => {
                window.cwcSendTavoCmd(`=对[${DATA.chat.targetName}]拉黑`);
            }, "danger", "确定删除", "取消");
        };

        window.cwcActionGreet = function() {
            window.cwcShowModal(`是否与[${DATA.chat.targetName}]打招呼？`, () => {
                const inputVal = document.getElementById('cwc-greet-input').value || "你好";
                window.cwcSendTavoCmd(`=对[${DATA.chat.targetName}]打招呼，打招呼信息为[${inputVal}]`);
            }, "normal", "发送", "取消", true);
        };

        // --- 核心：修改备注 ---
        window.cwcActionEditRemark = function() {
            let currentRemark = document.getElementById('prof-remark-text').innerText;
            if(currentRemark === '无' || currentRemark === '') currentRemark = '';
            let msg = `<div style="text-align:left; font-size:14px; color:#555;">设置备注名将同步至深层记忆。<br><input type="text" id="cwc-remark-input" class="cwc-input-field" value="${currentRemark}" placeholder="输入新备注..."></div>`;

            window.cwcShowModal(msg, async () => {
                const newVal = document.getElementById('cwc-remark-input').value.trim();
                const targetName = DATA.chat.targetName;
                try {
                    if (typeof tavo !== 'undefined') {
                        let rawStr = await tavo.get("NPC-" + targetName, "chat") || "";
                        if (rawStr) {
                            let reg = /(未知参数1:)(.*?)(;|\|)/g;
                            if (reg.test(rawStr)) {
                                rawStr = rawStr.replace(reg, `$1${newVal}$3`);
                            } else {
                                rawStr = rawStr.replace(/(未知参数2:)/g, `未知参数1:${newVal} | 未知参数2:`);
                            }
                            await tavo.set("NPC-" + targetName, rawStr, "chat");
                        }
                    }
                } catch(e) {}
                window.cwcSendTavoCmd(`=对[${targetName}]备注=${newVal}`);
            }, "normal", "确认修改", "取消"); 
        };

        // --- 核心：作品权限与购买 ---
        window.cwcActionBuyVideo = function(videoName, price) {
            let msg = price === 0 ? `确认解锁免费作品<br>《${videoName}》？` : `确认支付 <span style="color:#fa5151;">${price}元</span> 购买作品<br>《${videoName}》？`;
            window.cwcShowModal(msg, async () => {
                const targetName = DATA.chat.targetName;
                try {
                    if (typeof tavo !== 'undefined') {
                        let rawStr = await tavo.get("NPC-" + targetName, "chat") || "";
                        if (rawStr) {
                            // 由于使用了原生的未知参数2字符串记录（如：[作品名]-致盲是-收费50金币-（简述）-购买者[名单]）
                            // 这里交给 AI 识别指令后，由 AI 在下一轮的底层自愈脚本中将其名字写入购买者名单。
                            if (tavo.utils && tavo.utils.toast) tavo.utils.toast(`支付请求已发送，等待天宫系统验证...`);
                        }
                    }
                } catch(e) {}
                let cmd = price === 0 ? `=对[${targetName}]解锁了免费作品[${videoName}]` : `=对[${targetName}]购买了作品[${videoName}]:消费了${price}元`;
                window.cwcSendTavoCmd(cmd);
            }, "normal", "确认", "再想想");
        };

        // --- 渲染引擎 ---
        window.cwcRenderAll = function() {
            document.getElementById('cwc-title-render').innerText = DATA.chat.targetName;

            // 1. 渲染聊天
            let cHtml = "";
            DATA.chat.messages.forEach(msg => {
                if (msg.type === "time") {
                    cHtml += `<div class="chat-timestamp"><span>${msg.text}</span></div>`;
                } else if (msg.type === "sys") {
                    cHtml += `<div class="chat-sys-msg">${msg.text}</div>`;
                } else if (msg.type === "error") {
                    cHtml += `<div class="chat-error-msg" onclick="window.cwcActionGreet()">${msg.text}</div>`;
                } else if (msg.type === "left") {
                    cHtml += `
                    <div class="chat-row left">
                        <div class="chat-avatar" style="background-color: ${msg.color || '#555'};" onclick="window.cwcShowView('profile')">${msg.avatar}</div>
                        <div class="chat-bubble">${msg.text}</div>
                    </div>`;
                } else if (msg.type === "right") {
                    cHtml += `
                    <div class="chat-row right">
                        <div class="chat-avatar" style="background-color: ${msg.color || '#07c160'};">${msg.avatar}</div>
                        <div class="chat-bubble">${msg.text}</div>
                    </div>`;
                }
            });
            document.getElementById('cwc-render-msgs').innerHTML = cHtml;

            // 2. 渲染资料与备注
            const prof = DATA.profile;
            document.getElementById('prof-avatar').style.background = prof.color;
            document.getElementById('prof-avatar').innerText = prof.avatar;
            document.getElementById('prof-nickname').innerText = prof.nickname;
            document.getElementById('prof-gender').innerText = prof.gender;
            document.getElementById('prof-name').innerText = `姓名：${prof.name}`;
            document.getElementById('prof-loc').innerText = `地区：${prof.location}`;
            document.getElementById('prof-remark-text').innerText = prof.remark || "无";
            document.getElementById('prof-desc').innerText = prof.desc;

            // 3. 渲染天宫圈资产 (核心同调更新)
            if(prof.videos && prof.videos.length > 0) {
                document.getElementById('prof-tiangong-section').style.display = 'block';
                document.getElementById('prof-tiangong-rank').innerText = `${prof.tiangongRank}`;

                let total = prof.videos.length;
                let freeCount = prof.videos.filter(v => v.price === 0).length;
                let paidCount = total - freeCount;

                document.getElementById('prof-videos-stats').innerHTML = `公开影音 <span style="font-size:11px; color:#999; font-weight:normal;">作品数共${total}条，含免费${freeCount}条，付费${paidCount}条</span>`;

                document.getElementById('prof-videos-wrapper').style.display = 'block';
                let vHtml = "";

                prof.videos.forEach(v => {
                    let label = "";
                    let clickAction = "";
                    let opacity = 1;

                    // 权限锁死逻辑：需要互关但未互关
                    if (v.requiresMutual && !prof.mutualFollow) {
                        label = "🔒互粉可见";
                        clickAction = `window.cwcShowModal('该作品权限设定为致盲。仅限【天宫APP】互相关注的好友可见。', ()=>{window.cwcCloseModal();})`;
                        opacity = 0.6;
                    } 
                    // 已购买/解锁逻辑：直接展示，不再隐藏
                    else if (v.purchased) {
                        label = "✅已解锁";
                        clickAction = `window.cwcShowModal('正在播放：《${v.name}》<br><span style=\\'color:#999;font-size:12px;\\'>[系统提示：视频数据流已映射至您的终端设备]</span>', ()=>{window.cwcCloseModal();})`;
                    } 
                    // 免费未解锁逻辑
                    else if (v.price === 0) {
                        label = "免费解锁";
                        clickAction = `window.cwcActionBuyVideo('${v.name}', 0)`;
                    } 
                    // 付费未解锁逻辑
                    else {
