                        <div class="video-title" title="${v.name}">${v.name}</div>
                    </div>`;
                });
                document.getElementById('prof-videos-container').innerHTML = vHtml;

            } else {
                document.getElementById('prof-tiangong-section').style.display = 'none';
            }

            setTimeout(() => {
                const scrollArea = document.getElementById('cw-chat-scroll');
                if(scrollArea) scrollArea.scrollTop = scrollArea.scrollHeight;
            }, 150);
        };

        window.cwcRenderAll();
    </script>
